code = """import json, re

# Load JSON data from file paths provided by previous tool calls
with open(var_call_J533t7hDpFSBpOuPwuPzEkIF, 'r') as f:
    businesses = json.load(f)
with open(var_call_wjgnF1u86sWtcq2WVdEsOaRG, 'r') as f:
    reviews = json.load(f)

def extract_categories(rec):
    # Prefer explicit 'categories' field
    cats = []
    if 'categories' in rec and rec['categories'] not in (None, '', []):
        c = rec['categories']
        if isinstance(c, list):
            cats = [str(x).strip() for x in c if x]
        else:
            cats = [x.strip() for x in str(c).split(',') if x.strip()]
        return cats
    # Fallback: look for first single-quoted substring in description
    desc = rec.get('description') or ''
    if desc:
        m = re.search(r"'([^']+)'", desc)
        if m:
            content = m.group(1)
            parts = re.split(r',|/|;|&|\band\b', content)
            cats = [p.strip() for p in parts if p.strip()]
            return cats
    return []

# Build mapping from category -> set of business_ids that accept credit cards
cat_to_biz = {}
for b in businesses:
    attrs = b.get('attributes')
    if not isinstance(attrs, dict):
        continue
    if attrs.get('BusinessAcceptsCreditCards') != 'True':
        continue
    bizid = b.get('business_id')
    if not bizid:
        continue
    cats = extract_categories(b)
    for c in cats:
        cname = c.strip().strip("'\"")
        if cname:
            cat_to_biz.setdefault(cname, set()).add(bizid)

if not cat_to_biz:
    result = {"category": None, "business_count": 0, "average_rating": None}
else:
    # pick category with largest number of businesses (tie-breaker: alphabetical)
    best_cat, biz_set = sorted(cat_to_biz.items(), key=lambda kv: (-len(kv[1]), kv[0]))[0]
    biz_list = sorted(list(biz_set))
    bizrefs = set([b.replace('businessid_', 'businessref_') for b in biz_list])
    ratings = []
    for r in reviews:
        br = r.get('business_ref')
        if br in bizrefs:
            try:
                ratings.append(float(r.get('rating')))
            except:
                pass
    avg_rating = None
    if ratings:
        avg_rating = round(sum(ratings)/len(ratings), 3)
    result = {"category": best_cat, "business_count": len(biz_set), "average_rating": avg_rating}

print("__RESULT__:")
print(json.dumps(result))"""

